import React, { useEffect, useRef } from "react";

const DashboardCards = () => {

  // 🔹 Dummy data
  const total = 20;
  const completed = 15;
  const percent = Math.round((completed / total) * 100);

  const isCompleted = completed === total;

  // 🔹 Analog Clock Logic
  const hourRef = useRef();
  const minRef = useRef();
  const secRef = useRef();

  useEffect(() => {
  const interval = setInterval(() => {
    const now = new Date();

    const sec = now.getSeconds();
    const min = now.getMinutes();
    const hr = now.getHours();

    if (secRef.current && minRef.current && hourRef.current) {
      secRef.current.style.transform =
        `translate(-50%, -100%) rotate(${sec * 6}deg)`;

      minRef.current.style.transform =
        `translate(-50%, -100%) rotate(${min * 6}deg)`;

      hourRef.current.style.transform =
        `translate(-50%, -100%) rotate(${hr * 30 + min / 2}deg)`;
    }
  }, 1000);

  return () => clearInterval(interval);
}, []);

const handleAddTask = () => {
  console.log("Add task clicked");
};

  return (
    <div className="grid md:grid-cols-2 lg:grid-cols-4 gap-6 p-6">

      {/* 🔥 1. Progress Card */}
      <div className="bg-gradient-to-br flex flex-col items-center justify-center from-purple-600 to-indigo-600 p-6 rounded-2xl text-white shadow-lg hover:scale-105 transition">

        <div className="flex justify-center mb-4">
          <div className="relative w-28 h-28">
            <svg className="w-full h-full transform -rotate-90">
              <circle
                cx="56"
                cy="56"
                r="50"
                stroke="white"
                strokeWidth="8"
                fill="none"
                opacity="0.2"
              />
              <circle
                cx="56"
                cy="56"
                r="50"
                stroke="white"
                strokeWidth="8"
                fill="none"
                strokeDasharray={314}
                strokeDashoffset={314 - (314 * percent) / 100}
              />
            </svg>
            <div className="absolute inset-0 flex items-center justify-center text-xl font-bold">
              {percent}%
            </div>
          </div>
        </div>

        <p className="text-center">
          You've completed {completed} out of {total} tasks.
        </p>

        <p className="text-sm text-center mt-3 opacity-80">
          {isCompleted
            ? "🎉 Congratulations! All tasks done!"
            : "🚀 Keep going, you're doing great!"}
        </p>

                      {/* 🔘 Add Task Button */}
<div className="absolute -bottom-6 left-1/2 transform -translate-x-1/2"> 
    <button
    onClick={handleAddTask}
    className="mt-4 px-4 py-2 bg-white text-indigo-600 font-semibold rounded-lg shadow hover:bg-gray-100 transition"
  >
    + Add Task
  </button>
</div>
      </div>

     {/* 🔥 2. Analog Clock */}
<div className="bg-gradient-to-br from-pink-500 to-red-500 p-6 rounded-2xl text-white shadow-lg hover:scale-105 transition flex justify-center items-center">

  <div className="relative w-44 h-44  flex items-center justify-center">

    {/* 🔢 Numbers */}
    {[...Array(12)].map((_, i) => {
      const angle = (i + 1) * 30;
      return (
        <div
          key={i}
          className="absolute text-white text-sm font-bold drop-shadow"
          style={{
            transform: `rotate(${angle}deg) translate(0, -90px) rotate(-${angle}deg)`
          }}
        >
          {i + 1}
        </div>
      );
    })}

    {/* Hour */}
    <div
      ref={hourRef}
      className="absolute w-1 h-12 bg-white top-1/2 left-1/2 origin-bottom"
      style={{ transform: "translate(-50%, -100%) rotate(0deg)" }}
    />

    {/* Minute */}
    <div
      ref={minRef}
      className="absolute w-1 h-16 bg-white top-1/2 left-1/2 origin-bottom"
      style={{ transform: "translate(-50%, -100%) rotate(0deg)" }}
    />

    {/* Second */}
    <div
      ref={secRef}
      className="absolute w-[2px] h-20 bg-yellow-300 top-1/2 left-1/2 origin-bottom"
      style={{ transform: "translate(-50%, -100%) rotate(0deg)" }}
    />

    {/* Center dot */}
    <div className="w-3 h-3 bg-white rounded-full absolute z-10" />
  </div>

</div>

      {/* 🔥 3. Calendar */}
      <div className="bg-gradient-to-br from-green-500 to-teal-500 p-6 rounded-2xl text-white shadow-lg hover:scale-105 transition">

        <h3 className="text-lg font-semibold mb-3">📅 Calendar</h3>

        <div className="grid grid-cols-7 gap-2 text-center text-sm">
      {["Sun","Mon","Tue","Wed","Thu","Fri","Sat"].map((d, i) => (
  <div key={`day-${i}`} className="font-bold">{d}</div>
))}

{[...Array(30)].map((_, i) => (
  <div
    key={`date-${i}`}
    className={`p-2 rounded ${
      i === new Date().getDate() - 1
        ? "bg-white text-black"
        : "bg-white/20"
    }`}
  >
    {i + 1}
  </div>
))}
        </div>
      </div>

      {/* 🔥 4. Profile Card */}
      <div className="bg-gradient-to-br flex flex-col items-center justify-center from-blue-500 to-cyan-500 p-6 rounded-2xl text-white shadow-lg hover:scale-105 transition text-center">

        <img
          src="https://i.pravatar.cc/100"
          className="w-20 h-20 rounded-full mx-auto border-4 border-white"
          alt=""
        />

        <h3 className="mt-4 text-lg font-semibold">Priyanshu</h3>

        <button className="mt-4 px-4 py-2 bg-white text-black rounded-lg hover:bg-white/90 transition">
          Edit Profile
        </button>

      </div>

    </div>
  );
};

export default DashboardCards;
